20	/** @file*/
21	
22	#include "internal_nn_math.h"
23	#include "riscv_nn_support.h"
24	
25	//// Convolution Functions
26	
27	int32_t riscv_nn_conv_HWC_s16_s16_s16_sft_bias(const q15_t * in_tensor,
28	                            const uint16_t in_tensor_dim,
29	                            const uint16_t in_tensor_ch,
30	                            const q15_t * ker_weight,
31	                            const uint16_t out_tensor_ch,
32	                            const uint16_t ker_dim,
33	                            const uint16_t pad,
34	                            const uint16_t stride,
35	                            const q15_t * bias,
36	                            const uint16_t bias_lshift,
37	                            const uint16_t out_rshift,
38	                            q15_t * out_tensor,
39	                            const uint16_t out_tensor_dim,
40	                            q15_t * in_tmp_buf,
41	                            q7_t * tmp_buf)
42	{
43	#ifdef ENA_EMPTY_FUN
44	    //empty body
45	#elif (defined (ENA_VEC_ISA) || defined (ENA_DSP_ISA))
46	    int16_t   i_out_y, i_out_x, i_ker_y, i_ker_x;
47	
48	    q15_t    *pBuffer = in_tmp_buf;
49	    q15_t    *pOut = out_tensor;
50	    q15_t    *im_buffer = in_tmp_buf;
51	    const q15_t *pA;
52	    int       i;
53	#if defined(ENA_VEC_ISA) && defined(ENA_VEC_INTRINSIC)
54	    long colCnt2 = in_tensor_ch * ker_dim * ker_dim;
55	    long vl;
56	#elif defined(ENA_VEC_ISA)
57	    uint16_t colCnt2 = in_tensor_ch * ker_dim * ker_dim;
58	    int32_t vl;
59	    NDS_VEC_VSETVLI_E16(vl, in_tensor_ch);
60	    NDS_VEC_VAND_VI(NDS_VEC_V31, NDS_VEC_V31, 0);   //for nn_set_zero_s8
61	#endif
62	
63	    /* This part implements the im2col function */
64	    for (i_out_y = 0; i_out_y < out_tensor_dim; i_out_y++)
65	    {
66	        for (i_out_x = 0; i_out_x < out_tensor_dim; i_out_x++)
67	        {
68	            for (i_ker_y = i_out_y * stride - pad; i_ker_y < i_out_y * stride - pad + ker_dim; i_ker_y++)
69	            {
70	                for (i_ker_x = i_out_x * stride - pad; i_ker_x < i_out_x * stride - pad + ker_dim; i_ker_x++)
71	                {
72	                    if (i_ker_y < 0 || i_ker_y >= in_tensor_dim || i_ker_x < 0 || i_ker_x >= in_tensor_dim)
73	                    {
74	                        /* Filling 0 for out-of-bound paddings */
75	                        nn_set_zero_s16(pBuffer, in_tensor_ch);
76	                    }
77	                    else
78	                    {
79	                        nn_dup_s16((q15_t *) in_tensor + (i_ker_y * in_tensor_dim + i_ker_x) * in_tensor_ch, pBuffer, in_tensor_ch);
80	                    }
81	                    pBuffer += in_tensor_ch;
82	                }
83	            }
84	
85	#if defined(ENA_VEC_ISA) && defined(ENA_VEC_INTRINSIC)
86	            vl = __riscv_vsetvl_e32m8(colCnt2);
87	            pA = ker_weight;
88	            for (i = 0; i < out_tensor_ch; i++)
89	            {
90	                q31_t     sum = ((q31_t)bias[i] << bias_lshift) + NN_ROUND(out_rshift);
91	                q15_t    *pB = im_buffer;
92	
93	                //init
94	                vint32m1_t vsum = __riscv_vmv_v_x_i32m1(sum, vl);
95	                //clear v8~v15
96	                vint32m8_t vaccumulator = __riscv_vand(__riscv_vundefined_i32m8(), 0x0, vl);
97	
98	                long colCnt = colCnt2;
99	                while (colCnt > 0)
100	                {
101	                    vl = __riscv_vsetvl_e16m4(colCnt);
102	                    //load src1
103	                    vint16m4_t vsrc1 = __riscv_vle16_v_i16m4(pA, vl);
104	                    //load src2
105	                    vint16m4_t vsrc2 = __riscv_vle16_v_i16m4(pB, vl);
106	                    //acc += src1 * src2
107	                    vaccumulator = __riscv_vwmacc(vaccumulator, vsrc2, vsrc1, vl);
108	                    //bump pointers and update loop counter
109	                    colCnt -= vl;
110	                    pA += vl;
111	                    pB += vl;
112	                }
113	                vl = __riscv_vsetvl_e32m8(colCnt2);     //note the avl here
114	                vsum = __riscv_vredsum(vaccumulator, vsum, vl);
115	                //move vr results to gpr;
116	                sum = __riscv_vmv_x(vsum);
117	                *pOut = (q15_t) NDS_ISA_SATS((sum >> out_rshift), 16);
118	                pOut++;
119	            }
120	#elif defined(ENA_VEC_ISA)
121	            pA = ker_weight;
122	
123	            // 4-channel batched GEMM: process 4 output channels per iteration
124	            // using LMUL=M2 for loads, LMUL=M4 for accumulators
125	            // Register allocation:
126	            //   v0-v3:   acc0 (e32/M4)    v16-v17: weight ch0 (e16/M2)
127	            //   v4-v7:   acc1 (e32/M4)    v18-v19: weight ch1 (e16/M2)
128	            //   v8-v11:  acc2 (e32/M4)    v20-v21: weight ch2 (e16/M2)
129	            //   v12-v15: acc3 (e32/M4)    v22-v23: weight ch3 (e16/M2)
130	            //   v24-v25: input (e16/M2, shared across 4 channels)
131	            //   v26-v29: bias init scalars for VREDSUM
132	            for (i = 0; i + 3 < out_tensor_ch; i += 4)
133	            {
134	                q31_t     sum0 = ((q31_t)bias[i]     << bias_lshift) + NN_ROUND(out_rshift);
135	                q31_t     sum1 = ((q31_t)bias[i + 1] << bias_lshift) + NN_ROUND(out_rshift);
136	                q31_t     sum2 = ((q31_t)bias[i + 2] << bias_lshift) + NN_ROUND(out_rshift);
137	                q31_t     sum3 = ((q31_t)bias[i + 3] << bias_lshift) + NN_ROUND(out_rshift);
138	
139	                const q15_t *pA0 = pA;
140	                const q15_t *pA1 = pA + colCnt2;
141	                const q15_t *pA2 = pA + 2 * colCnt2;
142	                const q15_t *pA3 = pA + 3 * colCnt2;
143	                q15_t    *pB = im_buffer;
144	
145	                // clear accumulators v0, v4, v8, v12 (e32/M4)
146	                NDS_VEC_VSETVLI(vl, colCnt2, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M4);
147	                NDS_VEC_VAND_VI(NDS_VEC_V0, NDS_VEC_V0, 0x0);
148	                NDS_VEC_VAND_VI(NDS_VEC_V4, NDS_VEC_V4, 0x0);
149	                NDS_VEC_VAND_VI(NDS_VEC_V8, NDS_VEC_V8, 0x0);
150	                NDS_VEC_VAND_VI(NDS_VEC_V12, NDS_VEC_V12, 0x0);
151	
152	                uint16_t colCnt = colCnt2;
153	                while (colCnt > 0)
154	                {
155	                    NDS_VEC_VSETVLI(vl, colCnt, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M2);
156	                    // load input (shared across 4 channels)
157	                    NDS_VEC_VLH_V(NDS_VEC_V24, pB);
158	                    // load 4 weight rows
159	                    NDS_VEC_VLH_V(NDS_VEC_V16, pA0);
160	                    NDS_VEC_VLH_V(NDS_VEC_V18, pA1);
161	                    NDS_VEC_VLH_V(NDS_VEC_V20, pA2);
162	                    NDS_VEC_VLH_V(NDS_VEC_V22, pA3);
163	                    // acc += input * weight for each channel
164	                    NDS_VEC_VWMACC_VV(NDS_VEC_V0,  NDS_VEC_V24, NDS_VEC_V16);
165	                    NDS_VEC_VWMACC_VV(NDS_VEC_V4,  NDS_VEC_V24, NDS_VEC_V18);
166	                    NDS_VEC_VWMACC_VV(NDS_VEC_V8,  NDS_VEC_V24, NDS_VEC_V20);
167	                    NDS_VEC_VWMACC_VV(NDS_VEC_V12, NDS_VEC_V24, NDS_VEC_V22);
168	                    // bump pointers
169	                    colCnt -= vl;
170	                    pA0 += vl;
171	                    pA1 += vl;
172	                    pA2 += vl;
173	                    pA3 += vl;
174	                    pB += vl;
175	                }
176	
177	                // reduce each accumulator with bias init
178	                NDS_VEC_VSETVLI(vl, colCnt2, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M4);
179	
180	                NDS_VEC_VMV_S_X(NDS_VEC_V26, sum0);
181	                NDS_VEC_VREDSUM_VS(NDS_VEC_V26, NDS_VEC_V0, NDS_VEC_V26);
182	                NDS_VEC_VMV_X_S(sum0, NDS_VEC_V26);
183	
184	                NDS_VEC_VMV_S_X(NDS_VEC_V26, sum1);
185	                NDS_VEC_VREDSUM_VS(NDS_VEC_V26, NDS_VEC_V4, NDS_VEC_V26);
186	                NDS_VEC_VMV_X_S(sum1, NDS_VEC_V26);
187	
188	                NDS_VEC_VMV_S_X(NDS_VEC_V26, sum2);
189	                NDS_VEC_VREDSUM_VS(NDS_VEC_V26, NDS_VEC_V8, NDS_VEC_V26);
190	                NDS_VEC_VMV_X_S(sum2, NDS_VEC_V26);
191	
192	                NDS_VEC_VMV_S_X(NDS_VEC_V26, sum3);
193	                NDS_VEC_VREDSUM_VS(NDS_VEC_V26, NDS_VEC_V12, NDS_VEC_V26);
194	                NDS_VEC_VMV_X_S(sum3, NDS_VEC_V26);
195	
196	                // requant and store 4 outputs
197	                pOut[0] = (q15_t) NDS_ISA_SATS((sum0 >> out_rshift), 16);
198	                pOut[1] = (q15_t) NDS_ISA_SATS((sum1 >> out_rshift), 16);
199	                pOut[2] = (q15_t) NDS_ISA_SATS((sum2 >> out_rshift), 16);
200	                pOut[3] = (q15_t) NDS_ISA_SATS((sum3 >> out_rshift), 16);
201	                pOut += 4;
202	                pA += 4 * colCnt2;
203	            }
204	
205	            // remainder: process leftover channels one at a time
206	            for (; i < out_tensor_ch; i++)
207	            {
208	                q31_t     sum = ((q31_t)bias[i] << bias_lshift) + NN_ROUND(out_rshift);
209	                q15_t    *pB = im_buffer;
210	
211	                NDS_VEC_VSETVLI(vl, colCnt2, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
212	                NDS_VEC_VMV_S_X(NDS_VEC_V16, sum);
213	                NDS_VEC_VAND_VI(NDS_VEC_V8, NDS_VEC_V8, 0x0);
214	
215	                uint16_t colCnt = colCnt2;
216	                while (colCnt > 0)
217	                {
218	                    NDS_VEC_VSETVLI(vl, colCnt, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M4);
219	                    NDS_VEC_VLH_V(NDS_VEC_V0, pA);
220	                    NDS_VEC_VLH_V(NDS_VEC_V4, pB);
221	                    NDS_VEC_VWMACC_VV(NDS_VEC_V8, NDS_VEC_V4, NDS_VEC_V0);
222	                    colCnt -= vl;
223	                    pA += vl;
224	                    pB += vl;
225	                }
226	                NDS_VEC_VSETVLI(vl, colCnt2, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
227	                NDS_VEC_VREDSUM_VS(NDS_VEC_V16, NDS_VEC_V8, NDS_VEC_V16);
228	                NDS_VEC_VMV_X_S(sum, NDS_VEC_V16);
229	                *pOut = (q15_t) NDS_ISA_SATS((sum >> out_rshift), 16);
230	                pOut++;
231	            }
232	#elif defined(ENA_DSP_ISA_64)
233	            pA = ker_weight;
234	            for (i = 0; i < out_tensor_ch; i++)
235	            {
236	                long     sum = (uint32_t)(((q31_t)bias[i] << bias_lshift) + NN_ROUND(out_rshift));
237	                q15_t    *pB = im_buffer;
238	
239	                uint16_t  colCnt = in_tensor_ch * ker_dim * ker_dim >> 3;
240	                while (colCnt)
241	                {
242	                    long     inA1 = *__SIMD64(pA)++;
243	                    long     inB1 = *__SIMD64(pB)++;
244	                    long     inA2 = *__SIMD64(pA)++;
245	                    long     inB2 = *__SIMD64(pB)++;
246	
247	                    sum = NDS_DSP_KMADA(sum, inA1, inB1);
248	                    sum = NDS_DSP_KMADA(sum, inA2, inB2);
249	
250	                    colCnt--;
251	                }
252	                //sum up the high and low part 32-bit results
253	                sum = (q31_t)NDS_DSP_CRSA32(sum, sum);
254	
255	                colCnt = in_tensor_ch * ker_dim * ker_dim & 0x7;
256	                while (colCnt)
257	                {
258	                    q15_t     inA1 = *pA++;
259	                    q15_t     inB1 = *pB++;
260	                    sum += inA1 * inB1;
261	                    colCnt--;
262	                }
263	                *pOut = (q15_t) NDS_DSP_SATS((sum >> out_rshift), 16);
264	                pOut++;
265	            }
266	#else
267	            pA = ker_weight;
268	            for (i = 0; i < out_tensor_ch; i++)
269	            {
270	                q31_t     sum = ((q31_t)bias[i] << bias_lshift) + NN_ROUND(out_rshift);
271	                q15_t    *pB = im_buffer;
272	
273	                uint16_t  colCnt = in_tensor_ch * ker_dim * ker_dim >> 2;
274	                while (colCnt)
275	                {
276	                    q31_t     inA1 = *__SIMD32(pA)++;
277	                    q31_t     inB1 = *__SIMD32(pB)++;
278	                    q31_t     inA2 = *__SIMD32(pA)++;
279	                    q31_t     inB2 = *__SIMD32(pB)++;
280	
281	                    sum = NDS_DSP_KMADA(sum, inA1, inB1);
282	                    sum = NDS_DSP_KMADA(sum, inA2, inB2);
283	
284	                    colCnt--;
285	                }
286	                colCnt = in_tensor_ch * ker_dim * ker_dim & 0x3;
287	                while (colCnt)
288	                {
289	                    q15_t     inA1 = *pA++;
290	                    q15_t     inB1 = *pB++;
291	                    sum += inA1 * inB1;
292	                    colCnt--;
293	                }
294	                *pOut = (q15_t) NDS_DSP_SATS((sum >> out_rshift), 16);
295	                pOut++;
296	            }
297	#endif
298	
299	            /* counter reset */
300	            pBuffer = im_buffer;
301	        }
302	    }
303	
304	#else
305	    uint16_t  i, j, k, l, m, n;
306	    int       conv_out;
307	    long in_row, in_col;
308	
309	    for (i = 0; i < out_tensor_ch; i++)
310	    {
311	        for (j = 0; j < out_tensor_dim; j++)
312	        {
313	            for (k = 0; k < out_tensor_dim; k++)
314	            {
315	                conv_out = ((q31_t)bias[i] << bias_lshift) + NN_ROUND(out_rshift);
316	                for (m = 0; m < ker_dim; m++)
317	                {
318	                    for (n = 0; n < ker_dim; n++)
319	                    {
320	                        in_row = stride * j + m - pad;
321	                        in_col = stride * k + n - pad;
322	                        if (in_row >= 0 && in_col >= 0 && in_row < in_tensor_dim && in_col < in_tensor_dim)
323	                        {
324	                            for (l = 0; l < in_tensor_ch; l++)
325	                            {
326	                                conv_out +=
327	                                    in_tensor[(in_row * in_tensor_dim + in_col) * in_tensor_ch +
328	                                              l] * ker_weight[i * in_tensor_ch * ker_dim * ker_dim + (m * ker_dim +
329	                                                              n) * in_tensor_ch + l];
330	                            }
331	                        }
332	                    }
333	                }
334	                out_tensor[i + (j * out_tensor_dim + k) * out_tensor_ch] = (q15_t) NDS_ISA_SATS((conv_out >> out_rshift), 16);
335	            }
336	        }
337	    }
338	
339	#endif                          /* ENA_DSP_ISA */
340	
341	    return 0;
342	}
