20	/** @file*/
21	
22	#include "internal_nn_math.h"
23	#include "riscv_nn_support.h"
24	
25	//// Convolution Functions
26	
27	int32_t riscv_nn_conv_HWC_s16_s16_s16_sft_bias_fast(const q15_t * in_tensor,
28	                                 const uint16_t in_tensor_dim,
29	                                 const uint16_t in_tensor_ch,
30	                                 const q15_t * ker_weight,
31	                                 const uint16_t out_tensor_ch,
32	                                 const uint16_t ker_dim,
33	                                 const uint16_t pad,
34	                                 const uint16_t stride,
35	                                 const q15_t * bias,
36	                                 const uint16_t bias_lshift,
37	                                 const uint16_t out_rshift,
38	                                 q15_t * out_tensor,
39	                                 const uint16_t out_tensor_dim,
40	                                 q15_t * in_tmp_buf,
41	                                 q7_t * tmp_buf)
42	{
43	#ifdef ENA_EMPTY_FUN
44	    //empty body
45	#else
46	    if (in_tensor_ch % 2 != 0 || out_tensor_ch % 2 != 0)
47	    {
48	        /* check if the input dimension meets the constraints */
49	        return -1;
50	    }
51	
52	#if ((defined (ENA_VEC_ISA) && (NDS_VEC_RVV_VERSION >= 100)) || defined (ENA_DSP_ISA))
53	    int16_t   i_out_y, i_out_x, i_ker_y, i_ker_x;
54	    q15_t    *pBuffer = in_tmp_buf;
55	    q15_t    *pOut = out_tensor;
56	
57	#if defined(ENA_VEC_ISA) && defined(ENA_VEC_INTRINSIC)
58	    const long round = NN_ROUND(out_rshift);
59	    long colCnt2 = in_tensor_ch * ker_dim * ker_dim;
60	    long vl;
61	    vl = __riscv_vsetvl_e32m1(1);   // const zero for redsum
62	    vint32m1_t vsum = __riscv_vand(__riscv_vundefined_i32m1(), 0, vl);
63	#elif defined(ENA_VEC_ISA)
64	    const long round = NN_ROUND(out_rshift);
65	    uint16_t colCnt2 = in_tensor_ch * ker_dim * ker_dim;
66	    long vl;
67	    NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);   // const zero for redsum
68	    NDS_VEC_VAND_VI(NDS_VEC_V31, NDS_VEC_V31, 0);
69	#endif
70	
71	    for (i_out_y = 0; i_out_y < out_tensor_dim; i_out_y++)
72	    {
73	        for (i_out_x = 0; i_out_x < out_tensor_dim; i_out_x++)
74	        {
75	            /* This part implements the im2col function */
76	            for (i_ker_y = i_out_y * stride - pad; i_ker_y < i_out_y * stride - pad + ker_dim; i_ker_y++)
77	            {
78	                for (i_ker_x = i_out_x * stride - pad; i_ker_x < i_out_x * stride - pad + ker_dim; i_ker_x++)
79	                {
80	                    if (i_ker_y < 0 || i_ker_y >= in_tensor_dim || i_ker_x < 0 || i_ker_x >= in_tensor_dim)
81	                    {
82	                        nn_set_zero_s16(pBuffer, in_tensor_ch);
83	                    }
84	                    else
85	                    {
86	                        nn_dup_s16((q15_t *) in_tensor + (i_ker_y * in_tensor_dim + i_ker_x) * in_tensor_ch, pBuffer, in_tensor_ch);
87	                    }
88	                    pBuffer += in_tensor_ch;
89	                }
90	            }
91	
92	#if defined(ENA_VEC_ISA) && defined(ENA_VEC_INTRINSIC)
93	            if (i_out_x & 0x1)
94	            {
95	                const q15_t *pWt = ker_weight;
96	                q15_t *pOut2 = pOut + out_tensor_ch;
97	
98	                for (int i = 0; i < out_tensor_ch; i += 2)
99	                {
100	                    q15_t *pIn = in_tmp_buf;
101	                    const q15_t *pWt2 = pWt + in_tensor_ch * ker_dim * ker_dim;
102	                    const q15_t *pIn2 = pIn + in_tensor_ch * ker_dim * ker_dim;
103	
104	                    // clear the accumulators
105	                    vl = __riscv_vsetvl_e32m4(colCnt2);
