486	                NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
487	                NDS_VEC_VSRA_VX(NDS_VEC_V16, NDS_VEC_V16, out_rshift);
488	                NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M1);
489	                NDS_VEC_VNCLIP_WI(NDS_VEC_V16, NDS_VEC_V16, 0);
490	                NDS_VEC_VSE16_V(NDS_VEC_V16, pOut);
491	                pOut++;
492	            }
493	
494	            /* counter reset */
495	            pBuffer = in_tmp_buf;
496	        }
497	#elif defined(ENA_DSP_ISA_64)
498	        if(out_tensor_dim & 0x1)
499	        {
500	            /* setup the pointers for the weight matrix */
501	            const q15_t *pWt = ker_weight;
502	
503	            /* this loop over rows in the weight matrix */
504	            for (int i = 0; i < out_tensor_ch; i += 2)
505	            {
506	                /* setup pointers for the inputs */
507	                q15_t *pIn = in_tmp_buf;
508	
509	                /* setup the second pointer for weight */
510	                const q15_t *pWt2 = pWt + in_tensor_ch * ker_dim * ker_dim;
511	
512	                /* init the sum with bias */
513	                long sum1 = (uint32_t)(((q31_t)bias[i] << bias_lshift));
514	                long sum2 = (uint32_t)(((q31_t)bias[i + 1] << bias_lshift));
515	
516	                uint16_t  colCnt = in_tensor_ch * ker_dim * ker_dim >> 2;
517	                while (colCnt)
518	                {
519	                    long wt1_q15x4 = *__SIMD64(pWt)++;
520	                    long in_q15x4  = *__SIMD64(pIn)++;
521	                    long wt2_q15x4 = *__SIMD64(pWt2)++;
522	
523	                    sum1 = NDS_DSP_KMADA(sum1, wt1_q15x4, in_q15x4);
524	                    sum2 = NDS_DSP_KMADA(sum2, wt2_q15x4, in_q15x4);
525	
526	                    colCnt--;
527	                }
528	
529	                // Note. since in_tensor_ch is multilple of 2, the rest
530	                // could possibly be 2 or 0.
531	                colCnt = in_tensor_ch * ker_dim * ker_dim & 0x3;
532	                if(colCnt)
533	                {
534	                    long wt1_q15x2 = (uint32_t)*__SIMD32(pWt)++;
535	                    long in_q15x2  = (uint32_t)*__SIMD32(pIn)++;
536	                    long wt2_q15x2 = (uint32_t)*__SIMD32(pWt2)++;
537	
538	                    sum1 = NDS_DSP_KMADA(sum1, wt1_q15x2, in_q15x2);
539	                    sum2 = NDS_DSP_KMADA(sum2, wt2_q15x2, in_q15x2);
540	                }
541	
542	                //sum up the high and low part 32-bit results
543	                sum1 = NDS_DSP_CRSA32(sum1, sum1);
544	                sum2 = NDS_DSP_CRSA32(sum2, sum2);
545	
546	                sum1 = NDS_DSP_SRA32_U(sum1, out_rshift);
547	                sum2 = NDS_DSP_SRA32_U(sum2, out_rshift);
548	                *pOut++  = NDS_DSP_SATS(sum1, 16);
549	                *pOut++  = NDS_DSP_SATS(sum2, 16);
550	
551	                pWt += in_tensor_ch * ker_dim * ker_dim;
552	            }
553	
554	            // pOut += out_tensor_ch;
555	            /* counter reset */
556	            pBuffer = in_tmp_buf;
557	        }
558	#elif defined(ENA_DSP_ISA)
559	        if(out_tensor_dim & 0x1)
560	        {
561	            /* setup the pointers for the weight matrix */
562	            const q15_t *pWt = ker_weight;
563	
564	            /* this loop over rows in the weight matrix */
565	            for (int i = 0; i < out_tensor_ch; i += 2)
566	            {
567	                /* setup pointers for the inputs */
568	                q15_t *pIn = in_tmp_buf;
569	
570	                /* setup the second pointer for weight */
571	                const q15_t *pWt2 = pWt + in_tensor_ch * ker_dim * ker_dim;
572	
573	                /* init the sum with bias */
574	                q31_t sum1 = ((q31_t)bias[i] << bias_lshift) + NN_ROUND(out_rshift);
575	                q31_t sum2 = ((q31_t)bias[i + 1] << bias_lshift) + NN_ROUND(out_rshift);
576	
577	                uint16_t  colCnt = in_tensor_ch * ker_dim * ker_dim >> 1;
578	                while (colCnt)
579	                {
580	                    q31_t wt1_q15x2 = *__SIMD32(pWt)++;
581	                    q31_t in1_q15x2 = *__SIMD32(pIn)++;
582	                    q31_t wt2_q15x2 = *__SIMD32(pWt2)++;
583	
584	                    sum1 = NDS_DSP_KMADA(sum1, wt1_q15x2, in1_q15x2);
585	                    sum2 = NDS_DSP_KMADA(sum2, wt2_q15x2, in1_q15x2);
586	
587	                    colCnt--;
588	                }
589	
590	                // Note. since in_tensor_ch is multiple of 2, there is no
591	                // possible to have rest column.
592	                // colCnt = in_tensor_ch * ker_dim * ker_dim & 0x1;
593	                // while (colCnt)
594	                // {
595	                //     q15_t     inA1 = *pWt++;
596	                //     q15_t     inB1 = *pIn++;
597	                //     q15_t     inA2 = *pWt2++;
598	
599	                //     sum1 += inA1 * inB1;
600	                //     sum2 += inA2 * inB1;
601	                //     colCnt--;
602	                // }           /* while over colCnt */
603	                *pOut++ = NDS_DSP_SATS(sum1 >> out_rshift, 16);
604	                *pOut++ = NDS_DSP_SATS(sum2 >> out_rshift, 16);
605	
606	                pWt += in_tensor_ch * ker_dim * ker_dim;
607	            }
608	
609	            // pOut += out_tensor_ch;
610	            /* counter reset */
611	            pBuffer = in_tmp_buf;
612	        }
613	#endif
614	    }
615	#else
616	    uint16_t  i, j, k, l, m, n;
617	    int       conv_out;
618	    long in_row, in_col;
619	
620	    for (i = 0; i < out_tensor_ch; i++)
621	    {
622	        for (j = 0; j < out_tensor_dim; j++)
623	        {
624	            for (k = 0; k < out_tensor_dim; k++)
625	            {
626	                conv_out = ((q31_t)bias[i] << bias_lshift) + NN_ROUND(out_rshift);
627	                for (m = 0; m < ker_dim; m++)
628	                {
629	                    for (n = 0; n < ker_dim; n++)
630	                    {
631	                        in_row = stride * j + m - pad;
632	                        in_col = stride * k + n - pad;
633	                        if (in_row >= 0 && in_col >= 0 && in_row < in_tensor_dim && in_col < in_tensor_dim)
634	                        {
635	                            for (l = 0; l < in_tensor_ch; l++)
636	                            {
637	                                conv_out +=
638	                                    in_tensor[(in_row * in_tensor_dim + in_col) * in_tensor_ch + l]
639	                                    * ker_weight[i * in_tensor_ch * ker_dim * ker_dim + (m * ker_dim + n) * in_tensor_ch + l];
640	                            }
641	                        }
642	                    }
643	                }
644	                out_tensor[i + (j * out_tensor_dim + k) * out_tensor_ch] = (q15_t) NDS_ISA_SATS((conv_out >> out_rshift), 16);
645	            }
646	        }
647	    }
648	#endif                          /* ENA_DSP_ISA */
649	#endif  //ENA_EMPTY_FUN
650	
651	    /* Return to application */
652	    return 0;
653	}
