24	
25	//// Convolution Functions
26	
27	int32_t riscv_nn_conv_HWC_s16_s16_s16_sft_bias_fast_any(const q15_t * in_tensor,
28	                                     const uint16_t in_tensor_dim_x,
29	                                     const uint16_t in_tensor_dim_y,
30	                                     const uint16_t in_tensor_ch,
31	                                     const q15_t * ker_weight,
32	                                     const uint16_t out_tensor_ch,
33	                                     const uint16_t ker_dim_x,
34	                                     const uint16_t ker_dim_y,
35	                                     const uint16_t pad_x,
36	                                     const uint16_t pad_y,
37	                                     const uint16_t stride_x,
38	                                     const uint16_t stride_y,
39	                                     const q15_t * bias,
40	                                     const uint16_t bias_lshift,
41	                                     const uint16_t out_rshift,
42	                                     q15_t * out_tensor,
43	                                     const uint16_t out_tensor_dim_x,
44	                                     const uint16_t out_tensor_dim_y,
45	                                     q15_t * in_tmp_buf,
46	                                     q7_t * tmp_buf)
47	{
48	#ifdef ENA_EMPTY_FUN
49	    //empty body
50	#else
51	    if (in_tensor_ch % 2 != 0 || out_tensor_ch % 2 != 0)
52	    {
53	        /* check if the input dimension meets the constraints */
54	        return -1;
55	    }
56	
57	#if ((defined (ENA_VEC_ISA) && (NDS_VEC_RVV_VERSION >= 100)) || defined (ENA_DSP_ISA))
58	    int16_t   i_out_y, i_out_x, i_ker_y, i_ker_x;
59	    q15_t    *pBuffer = in_tmp_buf;
60	    q15_t    *pOut = out_tensor;
61	
62	#if defined(ENA_VEC_ISA) && defined(ENA_VEC_INTRINSIC)
63	    const long round = NN_ROUND(out_rshift);
64	    long colCnt2 = in_tensor_ch * ker_dim_x * ker_dim_y;
65	    long vl;
66	    long vlmax = __riscv_vsetvlmax_e32m1();
67	    vint32m1_t vzero = __riscv_vand(__riscv_vundefined_i32m1(), 0, vlmax);
68	#elif defined(ENA_VEC_ISA)
69	    const long round = NN_ROUND(out_rshift);
70	    uint16_t colCnt2 = in_tensor_ch * ker_dim_x * ker_dim_y;
71	    long vl;
72	    NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);   // const zero for redsum
73	    NDS_VEC_VAND_VI(NDS_VEC_V31, NDS_VEC_V31, 0);   //for nn_set_zero_s8
74	#endif
75	
76	    for (i_out_y = 0; i_out_y < out_tensor_dim_y; i_out_y++)
77	    {
78	        for (i_out_x = 0; i_out_x < out_tensor_dim_x; i_out_x++)
79	        {
80	            /* This part implements the im2col function */
81	            for (i_ker_y = i_out_y * stride_y - pad_y; i_ker_y < i_out_y * stride_y - pad_y + ker_dim_y; i_ker_y++)
82	            {
83	                for (i_ker_x = i_out_x * stride_x - pad_x; i_ker_x < i_out_x * stride_x - pad_x + ker_dim_x; i_ker_x++)
84	                {
85	                    if (i_ker_y < 0 || i_ker_y >= in_tensor_dim_y || i_ker_x < 0 || i_ker_x >= in_tensor_dim_x)
86	                    {
87	                        nn_set_zero_s16(pBuffer, in_tensor_ch);
88	                    }
89	                    else
90	                    {
91	                        nn_dup_s16((q15_t *) in_tensor + (i_ker_y * in_tensor_dim_x + i_ker_x) * in_tensor_ch, pBuffer, in_tensor_ch);
92	                    }
93	                    pBuffer += in_tensor_ch;
94	                }
95	            }
96	
97	#if defined(ENA_VEC_ISA) && defined(ENA_VEC_INTRINSIC)
98	            if (i_out_x & 0x1)
99	            {
100	                const q15_t *pWt = ker_weight;
101	                q15_t *pOut2 = pOut + out_tensor_ch;
102	
103	                for (int i = 0; i < out_tensor_ch; i += 2)
104	                {
105	                    q15_t *pIn = in_tmp_buf;
106	                    const q15_t *pWt2 = pWt + colCnt2;
107	                    const q15_t *pIn2 = pIn + colCnt2;
108	
109	                    // clear the accumulators
110	                    vl = __riscv_vsetvl_e32m4(colCnt2);
111	                    vint32m4_t vaccumulator_a = __riscv_vand(__riscv_vundefined_i32m4(), 0, vl);
112	                    vint32m4_t vaccumulator_b = __riscv_vand(__riscv_vundefined_i32m4(), 0, vl);
113	                    vint32m4_t vaccumulator_c = __riscv_vand(__riscv_vundefined_i32m4(), 0, vl);
114	                    vint32m4_t vaccumulator_d = __riscv_vand(__riscv_vundefined_i32m4(), 0, vl);
115	
116	                    long colCnt = colCnt2;
117	                    while (colCnt > 0)
118	                    {
119	                        vl = __riscv_vsetvl_e16m2(colCnt);
120	                        vint16m2_t vpWt = __riscv_vle16_v_i16m2(pWt, vl);
121	                        vint16m2_t vpIn = __riscv_vle16_v_i16m2(pIn, vl);
122	                        vint16m2_t vpWt2 = __riscv_vle16_v_i16m2(pWt2, vl);
123	                        vint16m2_t vpIn2 = __riscv_vle16_v_i16m2(pIn2, vl);
124	                        vaccumulator_a = __riscv_vwmacc(vaccumulator_a, vpWt, vpIn, vl);
125	                        vaccumulator_b = __riscv_vwmacc(vaccumulator_b, vpWt, vpIn2, vl);
126	                        vaccumulator_c = __riscv_vwmacc(vaccumulator_c, vpWt2, vpIn, vl);
127	                        vaccumulator_d = __riscv_vwmacc(vaccumulator_d, vpWt2, vpIn2, vl);
128	                        colCnt -= vl;
129	                        pWt += vl;
130	                        pWt2 += vl;
131	                        pIn += vl;
132	                        pIn2 += vl;
133	                    }
134	
135	                    vl = __riscv_vsetvl_e32m4(colCnt2);     //note the avl here
136	                    vint32m1_t vsum_a = __riscv_vget_i32m1(vaccumulator_a, 0);
137	                    vint32m1_t vsum_b = __riscv_vget_i32m1(vaccumulator_a, 2);
138	                    vint32m1_t vsum_c = __riscv_vget_i32m1(vaccumulator_a, 1);
139	                    vint32m1_t vsum_d = __riscv_vget_i32m1(vaccumulator_a, 3);
140	                    vsum_a = __riscv_vredsum(vaccumulator_a, vzero, vl);
141	                    vsum_b = __riscv_vredsum(vaccumulator_b, vzero, vl);
142	                    vsum_c = __riscv_vredsum(vaccumulator_c, vzero, vl);
143	                    vsum_d = __riscv_vredsum(vaccumulator_d, vzero, vl);
144	
145	                    vl = __riscv_vsetvl_e32m1(2);
146	                    vsum_a = __riscv_vslideup(vsum_a, vsum_c, 1, vl);
147	                    vsum_b = __riscv_vslideup(vsum_b, vsum_d, 1, vl);
148	
149	                    // add bias back
150	                    const q15_t *pInBias = &bias[i];
151	                    vint16mf2_t vpInBias_temp = __riscv_vle16_v_i16mf2(pInBias, vl);
152	                    vint32m1_t vpInBias = __riscv_vsext_vf2(vpInBias_temp, vl);
153	                    vpInBias = __riscv_vsll(vpInBias, bias_lshift, vl);
154	                    vpInBias = __riscv_vadd(vpInBias, round, vl);
155	                    vsum_a = __riscv_vadd(vsum_a, vpInBias, vl);
156	                    vsum_b = __riscv_vadd(vsum_b, vpInBias, vl);
157	
158	                    // right shift and clip the outputs
159	                    vsum_a = __riscv_vsra(vsum_a, out_rshift, vl);
160	                    vsum_b = __riscv_vsra(vsum_b, out_rshift, vl);
161	                    vl = __riscv_vsetvl_e16m1(vl);
162	                    vint32m2_t vresult_1_temp = __riscv_vundefined_i32m2();
163	                    vresult_1_temp = __riscv_vset(vresult_1_temp, 0, vsum_a);
164	                    vint16m1_t vresult_1 = __riscv_vnclip(vresult_1_temp, 0, __RISCV_VXRM_RNU, vl);
165	                    vint32m2_t vresult_2_temp = __riscv_vundefined_i32m2();
166	                    vresult_2_temp = __riscv_vset(vresult_2_temp, 0, vsum_b);
167	                    vint16m1_t vresult_2 = __riscv_vnclip(vresult_2_temp, 0, __RISCV_VXRM_RNU, vl);
168	                    __riscv_vse16(pOut, vresult_1, vl);
169	                    __riscv_vse16(pOut2, vresult_2, vl);
170	                    pOut += vl;
171	                    pOut2 += vl;
172	
173	                    pWt += colCnt2;
174	                }
175	
176	                pOut += out_tensor_ch;
177	                /* counter reset */
178	                pBuffer = in_tmp_buf;
179	            }
180	#elif defined(ENA_VEC_ISA)
181	            if (i_out_x & 0x1)
182	            {
183	                const q15_t *pWt = ker_weight;
184	                q15_t *pOut2 = pOut + out_tensor_ch;
185	
186	                for (int i = 0; i < out_tensor_ch; i += 2)
187	                {
188	                    q15_t *pIn = in_tmp_buf;
189	                    const q15_t *pWt2 = pWt + colCnt2;
190	                    const q15_t *pIn2 = pIn + colCnt2;
191	
192	                    // clear the accumulators
193	                    NDS_VEC_VSETVLI(vl, colCnt2, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M4);
194	                    NDS_VEC_VAND_VI(NDS_VEC_V0, NDS_VEC_V0, 0x0);
195	                    NDS_VEC_VAND_VI(NDS_VEC_V4, NDS_VEC_V4, 0x0);
196	                    NDS_VEC_VAND_VI(NDS_VEC_V8, NDS_VEC_V8, 0x0);
197	                    NDS_VEC_VAND_VI(NDS_VEC_V12, NDS_VEC_V12, 0x0);
198	
199	                    uint16_t colCnt = colCnt2;
200	                    while (colCnt > 0)
201	                    {
202	                        NDS_VEC_VSETVLI(vl, colCnt, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M2);
203	                        NDS_VEC_VLE16_V(NDS_VEC_V16, pWt);
204	                        NDS_VEC_VLE16_V(NDS_VEC_V20, pIn);
205	                        NDS_VEC_VLE16_V(NDS_VEC_V18, pWt2);
206	                        NDS_VEC_VLE16_V(NDS_VEC_V22, pIn2);
207	                        NDS_VEC_VWMACC_VV(NDS_VEC_V0, NDS_VEC_V16, NDS_VEC_V20);
208	                        NDS_VEC_VWMACC_VV(NDS_VEC_V4, NDS_VEC_V16, NDS_VEC_V22);
209	                        NDS_VEC_VWMACC_VV(NDS_VEC_V8, NDS_VEC_V18, NDS_VEC_V20);
210	                        NDS_VEC_VWMACC_VV(NDS_VEC_V12, NDS_VEC_V18, NDS_VEC_V22);
211	                        colCnt -= vl;
212	                        pWt += vl;
213	                        pWt2 += vl;
214	                        pIn += vl;
215	                        pIn2 += vl;
216	                    }
217	
218	                    NDS_VEC_VSETVLI(vl, colCnt2, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M4);     //note the avl here
219	                    NDS_VEC_VREDSUM_VS(NDS_VEC_V0, NDS_VEC_V0, NDS_VEC_V31);
220	                    NDS_VEC_VREDSUM_VS(NDS_VEC_V2, NDS_VEC_V4, NDS_VEC_V31);
221	                    NDS_VEC_VREDSUM_VS(NDS_VEC_V1, NDS_VEC_V8, NDS_VEC_V31);
222	                    NDS_VEC_VREDSUM_VS(NDS_VEC_V3, NDS_VEC_V12, NDS_VEC_V31);
223	
224	                    NDS_VEC_VSETVLI(vl, 2, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
225	                    NDS_VEC_VSLIDEUP_VI(NDS_VEC_V0, NDS_VEC_V1, 1);
226	                    NDS_VEC_VSLIDEUP_VI(NDS_VEC_V2, NDS_VEC_V3, 1);
227	
228	                    // add bias back
229	                    const q15_t *pInias = &bias[i];
230	                    NDS_VEC_VLE16_V(NDS_VEC_V5, pInias);
231	                    NDS_VEC_VSEXT_VF2(NDS_VEC_V4, NDS_VEC_V5);
232	                    NDS_VEC_VSLL_VX(NDS_VEC_V4, NDS_VEC_V4, bias_lshift);
233	                    NDS_VEC_VADD_VX(NDS_VEC_V4, NDS_VEC_V4, round);
234	                    NDS_VEC_VADD_VV(NDS_VEC_V0, NDS_VEC_V0, NDS_VEC_V4);
235	                    NDS_VEC_VADD_VV(NDS_VEC_V2, NDS_VEC_V2, NDS_VEC_V4);
236	
237	                    // right shift and clip the outputs
238	                    NDS_VEC_VSRA_VX(NDS_VEC_V0, NDS_VEC_V0, out_rshift);
239	                    NDS_VEC_VSRA_VX(NDS_VEC_V2, NDS_VEC_V2, out_rshift);
240	                    NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M1);
241	                    NDS_VEC_VNCLIP_WI(NDS_VEC_V0, NDS_VEC_V0, 0);
