if(out_tensor_dim & 1)
{
    const q15_t *pWt = ker_weight;

    // 4-channel batched GEMM for odd-dimension tail
    int i;
    for (i = 0; i + 3 < out_tensor_ch; i += 4)
    {
        q31_t     sum0 = ((q31_t)bias[i]     << bias_lshift) + NN_ROUND(out_rshift);
        q31_t     sum1 = ((q31_t)bias[i + 1] << bias_lshift) + NN_ROUND(out_rshift);
        q31_t     sum2 = ((q31_t)bias[i + 2] << bias_lshift) + NN_ROUND(out_rshift);
        q31_t     sum3 = ((q31_t)bias[i + 3] << bias_lshift) + NN_ROUND(out_rshift);

        const q15_t *pA0 = pWt;
        const q15_t *pA1 = pWt + colCnt2;
        const q15_t *pA2 = pWt + 2 * colCnt2;
        const q15_t *pA3 = pWt + 3 * colCnt2;
        q15_t    *pIn = in_tmp_buf;

        // clear accumulators v0, v4, v8, v12 (e32/M4)
        NDS_VEC_VSETVLI(vl, colCnt2, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M4);
        NDS_VEC_VAND_VI(NDS_VEC_V0, NDS_VEC_V0, 0x0);
        NDS_VEC_VAND_VI(NDS_VEC_V4, NDS_VEC_V4, 0x0);
        NDS_VEC_VAND_VI(NDS_VEC_V8, NDS_VEC_V8, 0x0);
        NDS_VEC_VAND_VI(NDS_VEC_V12, NDS_VEC_V12, 0x0);

        uint16_t colCnt = colCnt2;
        while (colCnt > 0)
        {
            NDS_VEC_VSETVLI(vl, colCnt, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M2);
            // load input (shared across 4 channels)
            NDS_VEC_VLH_V(NDS_VEC_V24, pIn);
            // load 4 weight rows
            NDS_VEC_VLH_V(NDS_VEC_V16, pA0);
            NDS_VEC_VLH_V(NDS_VEC_V18, pA1);
            NDS_VEC_VLH_V(NDS_VEC_V20, pA2);
            NDS_VEC_VLH_V(NDS_VEC_V22, pA3);
            // acc += input * weight for each channel
            NDS_VEC_VWMACC_VV(NDS_VEC_V0,  NDS_VEC_V24, NDS_VEC_V16);
            NDS_VEC_VWMACC_VV(NDS_VEC_V4,  NDS_VEC_V24, NDS_VEC_V18);
            NDS_VEC_VWMACC_VV(NDS_VEC_V8,  NDS_VEC_V24, NDS_VEC_V20);
            NDS_VEC_VWMACC_VV(NDS_VEC_V12, NDS_VEC_V24, NDS_VEC_V22);
            // bump pointers
            colCnt -= vl;
            pA0 += vl;
            pA1 += vl;
            pA2 += vl;
            pA3 += vl;
            pIn += vl;
        }

        // reduce each accumulator with bias init
        NDS_VEC_VSETVLI(vl, colCnt2, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M4);

        NDS_VEC_VMV_S_X(NDS_VEC_V26, sum0);
        NDS_VEC_VREDSUM_VS(NDS_VEC_V26, NDS_VEC_V0, NDS_VEC_V26);
        NDS_VEC_VMV_X_S(sum0, NDS_VEC_V26);

        NDS_VEC_VMV_S_X(NDS_VEC_V26, sum1);
        NDS_VEC_VREDSUM_VS(NDS_VEC_V26, NDS_VEC_V4, NDS_VEC_V26);
        NDS_VEC_VMV_X_S(sum1, NDS_VEC_V26);

        NDS_VEC_VMV_S_X(NDS_VEC_V26, sum2);
        NDS_VEC_VREDSUM_VS(NDS_VEC_V26, NDS_VEC_V8, NDS_VEC_V26);
        NDS_VEC_VMV_X_S(sum2, NDS_VEC_V26);

        NDS_VEC_VMV_S_X(NDS_VEC_V26, sum3);
        NDS_VEC_VREDSUM_VS(NDS_VEC_V26, NDS_VEC_V12, NDS_VEC_V26);
        NDS_VEC_VMV_X_S(sum3, NDS_VEC_V26);

        // requant and store 4 outputs
        pOut[0] = (q15_t) NDS_ISA_SATS((sum0 >> out_rshift), 16);
        pOut[1] = (q15_t) NDS_ISA_SATS((sum1 >> out_rshift), 16);
        pOut[2] = (q15_t) NDS_ISA_SATS((sum2 >> out_rshift), 16);
        pOut[3] = (q15_t) NDS_ISA_SATS((sum3 >> out_rshift), 16);
        pOut += 4;
        pWt += 4 * colCnt2;
    }

    // remainder: process leftover channels one at a time
    for (; i < out_tensor_ch; i++)
    {
        q31_t     sum = ((q31_t)bias[i] << bias_lshift) + NN_ROUND(out_rshift);
        q15_t    *pIn = in_tmp_buf;

        NDS_VEC_VSETVLI(vl, colCnt2, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
        NDS_VEC_VMV_S_X(NDS_VEC_V16, sum);
        NDS_VEC_VAND_VI(NDS_VEC_V8, NDS_VEC_V8, 0x0);

        uint16_t colCnt = colCnt2;
        while (colCnt > 0)
        {
            NDS_VEC_VSETVLI(vl, colCnt, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M4);
            NDS_VEC_VLH_V(NDS_VEC_V0, pWt);
            NDS_VEC_VLH_V(NDS_VEC_V4, pIn);
            NDS_VEC_VWMACC_VV(NDS_VEC_V8, NDS_VEC_V4, NDS_VEC_V0);
            colCnt -= vl;
            pWt += vl;
            pIn += vl;
        }
        NDS_VEC_VSETVLI(vl, colCnt2, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
        NDS_VEC_VREDSUM_VS(NDS_VEC_V16, NDS_VEC_V8, NDS_VEC_V16);
        NDS_VEC_VMV_X_S(sum, NDS_VEC_V16);
        *pOut = (q15_t) NDS_ISA_SATS((sum >> out_rshift), 16);
        pOut++;
    }

    /* counter reset */
    pBuffer = in_tmp_buf;
}

